const input = $input.first().json;
const callback = input.callback_query;

if (!callback) {
  return [
    {
      json: {
        validCallback: false,
        error: "This is not a callback query.",
        responseText: "This is not a callback query.",
        debugInput: input
      }
    }
  ];
}

const data = String(callback.data || "").replace(/^=/, "");
const [action, questionId] = data.split("|");

const allowedActions = ["approve", "revise", "reject"];

const chatId =
  callback.message?.chat?.id ||
  callback.from?.id ||
  59229320;

if (!allowedActions.includes(action)) {
  return [
    {
      json: {
        validCallback: false,
        error: `Unknown action: ${action}`,
        callbackData: data,
        callbackQueryId: callback.id,
        telegramChatId: String(chatId),
        responseText: `Unknown action: ${action}`
      }
    }
  ];
}

if (!questionId) {
  return [
    {
      json: {
        validCallback: false,
        error: "Missing questionId in callback data.",
        callbackData: data,
        callbackQueryId: callback.id,
        telegramChatId: String(chatId),
        responseText: "Missing question ID."
      }
    }
  ];
}

const actionLabels = {
  approve: "Selected action: approve question and write it to database.",
  revise: "Selected action: revise question.",
  reject: "Selected action: reject question."
};

return [
  {
    json: {
      validCallback: true,
      action,
      questionId,
      callbackQueryId: callback.id,
      telegramChatId: String(chatId),
      telegramMessageId: callback.message?.message_id,
      telegramFromId: callback.from?.id,
      callbackData: data,
      responseText: `${actionLabels[action]}\n\nQuestion ID:\n${questionId}`
    }
  }
];

