function fail(message, errorType = "validation_error") {
  const input = $input.item?.json || {};

  return [
    {
      json: {
        valid: false,
        error: message,
        errorType,
        telegramChatId: input.message?.chat?.id || input.telegramChatId || null,
        telegramFromId: input.message?.from?.id || input.telegramFromId || null,
        originalTelegramMessageId: input.message?.message_id || input.originalTelegramMessageId || null,
        generationOptions: input.generationOptions || null
      }
    }
  ];
}

function isMissing(value) {
  return (
    value === undefined ||
    value === null ||
    String(value).trim() === "" ||
    String(value).trim().toLowerCase() === "undefined" ||
    String(value).trim().toLowerCase() === "null"
  );
}

function translitUk(value) {
  return String(value || "")
    .toLowerCase()
    .trim()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\u0449/g, "shch")
    .replace(/\u0448/g, "sh")
    .replace(/\u0447/g, "ch")
    .replace(/\u0436/g, "zh")
    .replace(/\u0445/g, "kh")
    .replace(/\u0446/g, "ts")
    .replace(/\u044e/g, "iu")
    .replace(/\u044f/g, "ia")
    .replace(/\u0454/g, "ie")
    .replace(/\u0457/g, "i")
    .replace(/\u0456/g, "i")
    .replace(/\u0491/g, "g")
    .replace(/\u0439/g, "i")
    .replace(/\u0430/g, "a")
    .replace(/\u0431/g, "b")
    .replace(/\u0432/g, "v")
    .replace(/\u0433/g, "h")
    .replace(/\u0434/g, "d")
    .replace(/\u0435/g, "e")
    .replace(/\u0437/g, "z")
    .replace(/\u0438/g, "y")
    .replace(/\u043a/g, "k")
    .replace(/\u043b/g, "l")
    .replace(/\u043c/g, "m")
    .replace(/\u043d/g, "n")
    .replace(/\u043e/g, "o")
    .replace(/\u043f/g, "p")
    .replace(/\u0440/g, "r")
    .replace(/\u0441/g, "s")
    .replace(/\u0442/g, "t")
    .replace(/\u0443/g, "u")
    .replace(/\u0444/g, "f")
    .replace(/\u044c/g, "");
}

function slugify(value) {
  return translitUk(value)
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 60);
}

function randomId(length = 4) {
  const chars = "abcdefghijklmnopqrstuvwxyz0123456789";
  let result = "";

  for (let i = 0; i < length; i++) {
    result += chars[Math.floor(Math.random() * chars.length)];
  }

  return result;
}

function normalizeQuestionType(value) {
  const raw = String(value || "")
    .trim()
    .toUpperCase()
    .replace(/[\s-]+/g, "_")
    .replace(/_+/g, "_");

  const aliases = {
    SINGLECHOICE: "SINGLE_CHOICE",
    SINGLE_CHOICE: "SINGLE_CHOICE",

    MULTIPLECHOICE: "MULTIPLE_CHOICE",
    MULTIPLE_CHOICE: "MULTIPLE_CHOICE",

    TRUEFALSE: "TRUE_FALSE",
    TRUE_FALSE: "TRUE_FALSE",

    FILLINTHEBLANK: "FILL_IN_THE_BLANK",
    FILL_IN_THE_BLANK: "FILL_IN_THE_BLANK",

    TEXTINPUT: "TEXT_INPUT",
    TEXT_INPUT: "TEXT_INPUT",

    IMAGECHOICE: "IMAGE_CHOICE",
    IMAGE_CHOICE: "IMAGE_CHOICE",

    READINGCOMPREHENSION: "READING_COMPREHENSION",
    READING_COMPREHENSION: "READING_COMPREHENSION",

    SLIDERSCALE: "SLIDER_SCALE",
    SLIDER_SCALE: "SLIDER_SCALE",

    TENFACTS: "TEN_FACTS",
    TEN_FACTS: "TEN_FACTS",

    SEQUENCE: "SEQUENCE",
    MATCHING: "MATCHING",
    COMPARISON: "COMPARISON"
  };

  return aliases[raw] || raw;
}

function toIntOrDefault(value, fallback) {
  const n = Number(value);
  return Number.isInteger(n) && n > 0 ? n : fallback;
}

function formatAnswerPreview(data) {
  if (Array.isArray(data.answers)) {
    return data.answers
      .map((answer, index) => {
        const isCorrect =
          Array.isArray(data.correctAnswerIndices) &&
          data.correctAnswerIndices.includes(index);

        return `${index + 1}. ${answer}${isCorrect ? " - correct" : ""}`;
      })
      .join("\n");
  }

  if (data.type === "TRUE_FALSE") {
    return `Correct answer: ${data.correctAnswer ? "true" : "false"}`;
  }

  if (Array.isArray(data.correctAnswers)) {
    return `Correct answers: ${data.correctAnswers.join(", ")}`;
  }

  if (data.type === "MATCHING") {
    return [
      "Left side:",
      ...(data.leftSide || []).map((x, i) => `${i + 1}. ${x}`),
      "",
      "Right side:",
      ...(data.rightSide || []).map((x, i) => `${i + 1}. ${x}`)
    ].join("\n");
  }

  if (data.type === "COMPARISON") {
    return [
      "Categories:",
      ...(data.categories || []).map((x, i) => `${i + 1}. ${x}`),
      "",
      "Statements:",
      ...(data.statements || []).map((x, i) => `${i + 1}. ${x.text}`)
    ].join("\n");
  }

  return "Preview is not configured for this question type.";
}

function formatReason(value) {
  return String(value || "")
    .replace(/_/g, " ")
    .trim();
}

const input = $input.item.json;
const generationOptions = input.generationOptions || {};
const messageText = input.message?.text;

if (!messageText) {
  return fail("Telegram message has no text.");
}

if (messageText.startsWith("/")) {
  return fail("This is a Telegram command, not question JSON.");
}

let payload;

try {
  payload = JSON.parse(messageText);
} catch (error) {
  return fail("Message is not valid JSON.");
}

if (!payload || typeof payload !== "object" || Array.isArray(payload)) {
  return fail("Parsed JSON must be an object.");
}

if (payload.status === "insufficient_sources") {
  return fail(
    payload.reason || "Insufficient sources for question generation.",
    "insufficient_sources"
  );
}

if (!payload.data && Array.isArray(payload.questions) && payload.questions.length > 0) {
  const firstQuestion = payload.questions[0];

  payload = {
    categoryId: !isMissing(firstQuestion.categoryId)
      ? firstQuestion.categoryId
      : !isMissing(payload.categoryId)
        ? payload.categoryId
        : generationOptions.categoryId,

    levelId: !isMissing(firstQuestion.levelId)
      ? firstQuestion.levelId
      : !isMissing(payload.levelId)
        ? payload.levelId
        : generationOptions.levelId,

    num: !isMissing(firstQuestion.num)
      ? firstQuestion.num
      : !isMissing(payload.num)
        ? payload.num
        : generationOptions.num ?? 1,

    block: !isMissing(firstQuestion.block)
      ? firstQuestion.block
      : !isMissing(payload.block)
        ? payload.block
        : generationOptions.block,

    slug: firstQuestion.slug || payload.slug,
    data: firstQuestion.data || firstQuestion
  };
}

payload.categoryId = isMissing(payload.categoryId)
  ? generationOptions.categoryId
  : payload.categoryId;

payload.levelId = isMissing(payload.levelId)
  ? generationOptions.levelId
  : payload.levelId;

payload.block = isMissing(payload.block)
  ? generationOptions.block
  : payload.block;

payload.num = !isMissing(generationOptions.num)
  ? generationOptions.num
  : isMissing(payload.num)
    ? 1
    : payload.num;

if (payload.data && typeof payload.data === "object") {
  if (isMissing(payload.data.type) && generationOptions.type) {
    payload.data.type = generationOptions.type;
  }

  payload.data.type = normalizeQuestionType(payload.data.type);
}

const allowedCategories = [
  "erudite",
  "science",
  "philosophy",
  "culture",
  "noesis",
  "agora"
];

const allowedTypes = [
  "SINGLE_CHOICE",
  "MULTIPLE_CHOICE",
  "TRUE_FALSE",
  "SEQUENCE",
  "MATCHING",
  "COMPARISON",
  "TEXT_INPUT",
  "FILL_IN_THE_BLANK",
  "IMAGE_CHOICE",
  "READING_COMPREHENSION",
  "SLIDER_SCALE",
  "TEN_FACTS"
];

const categoryId = String(payload.categoryId || "");
const levelId = String(payload.levelId || "");
const num = Number(payload.num);
const block = String(payload.block || "").toUpperCase();
const rawSlug = payload.slug;
const data = payload.data;

if (!allowedCategories.includes(categoryId)) {
  return fail("Invalid categoryId.");
}

if (!levelId) {
  return fail("Missing levelId.");
}

if (!Number.isInteger(num) || num < 1 || num > 999) {
  return fail("num must be an integer from 1 to 999.");
}

if (!/^[A-Z]$/.test(block)) {
  return fail("block must be one uppercase letter.");
}

if (!data || typeof data !== "object") {
  return fail("Missing data object.");
}

if (data.lang !== "ua") {
  return fail("data.lang must be ua.");
}

data.type = normalizeQuestionType(data.type || generationOptions.type);

if (!allowedTypes.includes(data.type)) {
  return fail("Invalid question type.");
}

if (!Array.isArray(data.topics) || data.topics.length === 0) {
  return fail("data.topics must be a non-empty array.");
}

if (!data.question && !["READING_COMPREHENSION", "SLIDER_SCALE"].includes(data.type)) {
  return fail("data.question is required for this question type.");
}

if (data.provenance && typeof data.provenance !== "object") {
  return fail("data.provenance must be an object.");
}

if (data.provenance?.sourceIds && !Array.isArray(data.provenance.sourceIds)) {
  return fail("data.provenance.sourceIds must be an array.");
}

if (Array.isArray(data.correctAnswerIndices)) {
  data.correctAnswerIndices = data.correctAnswerIndices.map(Number);
}

let outputGenerationOptions = generationOptions;
const requestedType = normalizeQuestionType(
  generationOptions.requestedType ||
  generationOptions.questionTypeResolution?.requestedType ||
  generationOptions.originalRequestedType ||
  ""
);

if (
  requestedType === "AUTO" &&
  data.type === "MULTIPLE_CHOICE" &&
  Array.isArray(data.correctAnswerIndices) &&
  data.correctAnswerIndices.length === 1
) {
  data.type = "SINGLE_CHOICE";
  payload.data.type = data.type;

  outputGenerationOptions = {
    ...generationOptions,
    type: data.type,
    resolvedQuestionType: data.type,
    questionTypeResolution: {
      ...(generationOptions.questionTypeResolution || {}),
      requestedType: generationOptions.questionTypeResolution?.requestedType || requestedType,
      resolvedType: data.type,
      auto: true,
      repairedFrom: "MULTIPLE_CHOICE",
      repairReason: "auto_multiple_choice_single_correct"
    }
  };
}

switch (data.type) {
  case "SINGLE_CHOICE":
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail("SINGLE_CHOICE must have exactly 6 answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length !== 1) {
      return fail("SINGLE_CHOICE must have exactly one correctAnswerIndices item.");
    }
    break;

  case "MULTIPLE_CHOICE":
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail("MULTIPLE_CHOICE must have exactly 6 answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length < 2) {
      return fail("MULTIPLE_CHOICE must have at least two correct indices.");
    }
    break;

  case "TRUE_FALSE":
    if (typeof data.correctAnswer !== "boolean") {
      return fail("TRUE_FALSE must have boolean correctAnswer.");
    }
    break;

  case "SEQUENCE":
    if (!Array.isArray(data.answers) || data.answers.length < 4 || data.answers.length > 6) {
      return fail("SEQUENCE must have 4 to 6 answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length !== data.answers.length) {
      return fail("SEQUENCE correctAnswerIndices must match answers length.");
    }
    break;

  case "MATCHING":
    if (!Array.isArray(data.leftSide) || !Array.isArray(data.rightSide) || !Array.isArray(data.correctMatches)) {
      return fail("MATCHING must have leftSide, rightSide and correctMatches.");
    }
    break;

  case "COMPARISON":
    if (!Array.isArray(data.categories) || !Array.isArray(data.statements)) {
      return fail("COMPARISON must have categories and statements.");
    }
    break;

  case "TEXT_INPUT":
  case "FILL_IN_THE_BLANK":
    if (!Array.isArray(data.correctAnswers) || data.correctAnswers.length === 0) {
      return fail(`${data.type} must have correctAnswers.`);
    }
    break;

  case "IMAGE_CHOICE":
    if (!Array.isArray(data.answers) || !Array.isArray(data.correctAnswerIndices)) {
      return fail("IMAGE_CHOICE must have answers and correctAnswerIndices.");
    }
    break;

  case "READING_COMPREHENSION":
    if (!data.text1 || !data.text2 || !Array.isArray(data.questions)) {
      return fail("READING_COMPREHENSION must have text1, text2 and questions.");
    }
    break;

  case "SLIDER_SCALE":
    if (!data.text || !Array.isArray(data.sliders)) {
      return fail("SLIDER_SCALE must have text and sliders.");
    }
    break;

  case "TEN_FACTS":
    if (!Array.isArray(data.answers) || data.answers.length !== 6) {
      return fail("TEN_FACTS must have exactly 6 answers.");
    }

    if (!Array.isArray(data.correctAnswerIndices) || data.correctAnswerIndices.length !== 1) {
      return fail("TEN_FACTS must have one correct index.");
    }

    if (!Array.isArray(data.facts) || data.facts.length === 0) {
      return fail("TEN_FACTS must have facts.");
    }
    break;
}

const difficulty = toIntOrDefault(
  data.difficulty || generationOptions.difficulty,
  1
);

const discipline =
  data.discipline ||
  generationOptions.discipline ||
  generationOptions.sourcePolicy?.discipline ||
  "general";

data.difficulty = difficulty;
data.discipline = discipline;

const numPart = String(num).padStart(2, "0");
const slug = slugify(rawSlug || data.question || data.type);
const questionId = `${data.lang}--${numPart}--${block}--${slug}--${randomId()}`;
const now = new Date().toISOString();

const documentData = {
  ...data,
  categoryId,
  levelId,
  questionId,
  num,
  block,
  slug,
  difficulty,
  discipline,
  status: "pending_review",
  source: "telegram-n8n",
  createdAt: now,
  updatedAt: now
};

const sourceQualityText = generationOptions.researchEnabled
  ? [
      `Source quality: ${generationOptions.sourceBriefQuality || "unknown"}`,
      `Source confidence: ${generationOptions.sourceConfidence ?? "unknown"}`,
      generationOptions.sourceSufficiency?.reason
        ? `Source sufficiency: ${formatReason(generationOptions.sourceSufficiency.reason)}`
        : null
    ].filter(Boolean).join("\n")
  : null;

const previewText = [
  "New question for moderation",
  "",
  `Category: ${categoryId}`,
  `Level: ${levelId}`,
  `Difficulty: ${difficulty}`,
  `Discipline: ${discipline}`,
  `Block: ${block}`,
  `Type: \`${data.type}\``,
  `ID: ${questionId}`,
  `Topics: ${data.topics.join(", ")}`,
  sourceQualityText,
  "",
  "Question:",
  data.question || data.text || "No short question text",
  "",
  "Answers:",
  formatAnswerPreview(data),
  "",
  data.explanation ? `Explanation:\n${data.explanation}` : "Explanation: missing",
  "",
  data.provenance?.sourceIds?.length
    ? `Sources:\n${data.provenance.sourceIds.join("\n")}`
    : null,
  "",
  "Actions:",
  "approve / reject / revise"
].filter(Boolean).join("\n");

return [
  {
    json: {
      valid: true,
      categoryId,
      levelId,
      questionId,
      collectionPath: generationOptions.collectionPath || `${categoryId}/${levelId}/questions`,
      levelDocumentPath: generationOptions.levelDocumentPath || `${categoryId}/${levelId}`,
      pendingCollectionPath: "pendingQuestions",
      documentData,
      previewText,
      telegramChatId: input.message.chat.id,
      telegramFromId: input.message.from.id,
      originalTelegramMessageId: input.message.message_id,
      generationOptions: outputGenerationOptions || null,
      targetResolution: generationOptions.targetResolution || null,
      difficulty,
      discipline
    }
  }
];

const text = String($json.message?.text || "").trim();

function getParam(name, defaultValue = "") {
  const match = text.match(new RegExp(`(?:^|\\s)${name}=`, "i"));

  if (!match || match.index === undefined) {
    return defaultValue;
  }

  let rest = text.slice(match.index + match[0].length).trimStart();

  // Tolerate accidental doubled opening quote: topic=""?????? ??????".
  while (rest.startsWith(`""`)) {
    rest = rest.slice(1);
  }

  if (rest.startsWith(`"`)) {
    const end = rest.indexOf(`"`, 1);
    if (end > 0) {
      return rest.slice(1, end).trim();
    }

    return rest.slice(1).trim();
  }

  const nextParam = rest.search(/\s+[A-Za-z][A-Za-z0-9_]*=/);
  const raw = nextParam >= 0 ? rest.slice(0, nextParam) : rest;

  return raw.trim();
}

const mode = text.startsWith("/generate_quiz")
  ? "quiz"
  : text.startsWith("/generate_question")
    ? "question"
    : "unknown";

if (mode === "unknown") {
  return [
    {
      json: {
        ok: false,
        error: "Unknown command. Use /generate_question or /generate_quiz.",
        telegramChatId: $json.message.chat.id
      }
    }
  ];
}

const topic = getParam("topic", "");
const categoryId = getParam("categoryId", "auto").toLowerCase();
const levelId = String(getParam("levelId", "auto"));
const block = String(getParam("block", "auto")).toUpperCase();
const rawNumParam = getParam("num", "auto");
const rawType = getParam("type", "SINGLE_CHOICE").toUpperCase();
const type = rawType;

let requestedCount = Number(getParam("count", mode === "quiz" ? "5" : "1"));

if (!Number.isFinite(requestedCount) || requestedCount < 1) {
  requestedCount = mode === "quiz" ? 5 : 1;
}

const maxQuizCount = 10;

let count = requestedCount;

if (mode === "question") {
  count = 1;
}

if (mode === "quiz" && count > maxQuizCount) {
  count = maxQuizCount;
}

const saveToDb = /(?:^|\s)db=on(?:\s|$)/i.test(text);
const sendDocument = !/(?:^|\s)doc=off(?:\s|$)/i.test(text);

const format = getParam("format", "markdown").toLowerCase();

const reviewEnabled = ["on", "true", "1", "yes"].includes(
  String(getParam("review", "off")).toLowerCase()
);

const autoReview = !["off", "false", "0", "no"].includes(
  String(getParam("autoReview", "on")).toLowerCase()
);

const reviewReason = null;

const researchEnabled = ["on", "true", "1", "yes"].includes(
  String(getParam("research", "off")).toLowerCase()
);

const deepResearch = ["on", "true", "1", "yes"].includes(
  String(getParam("deep", "off")).toLowerCase()
);

let sourceLimit = Number(getParam("sources", "3"));

if (!Number.isFinite(sourceLimit) || sourceLimit < 1) {
  sourceLimit = 3;
}

sourceLimit = Math.min(sourceLimit, 5);

const researchProvider = getParam("provider", "openalex").toLowerCase();

const targetAuto = {
  categoryId: categoryId === "auto",
  levelId: levelId.toLowerCase() === "auto",
  block: block.toLowerCase() === "auto",
  num: String(rawNumParam).toLowerCase() === "auto"
};

const explicitNum = targetAuto.num ? null : Number(rawNumParam);

if (!topic) {
  return [
    {
      json: {
        ok: false,
        error: "Missing topic. Example: /generate_question topic=\"Kyivska Rus\" db=off doc=on",
        telegramChatId: $json.message.chat.id
      }
    }
  ];
}

return [
  {
    json: {
      ok: true,
      mode,
      topic,
      categoryId,
      levelId,
      block,
      type,
      count,
      requestedCount,
      maxQuizCount,
      countWasLimited: mode === "quiz" && requestedCount > maxQuizCount,
      saveToDb,
      sendDocument,
      format,
      researchEnabled,
      reviewEnabled,
      autoReview,
      reviewReason,
      deepResearch,
      sourceLimit,
      targetAuto,
      explicitNum,
      researchProvider,
      originalCommand: text,
      telegramChatId: $json.message.chat.id,
      telegramFromId: $json.message.from.id,
      originalTelegramMessageId: $json.message.message_id
    }
  }
];

const input = $input.first().json;

const aiText =
  input.output_text ||
  input.output?.[0]?.content?.[0]?.text ||
  input.output?.[0]?.content?.find?.((c) => c.type === "output_text")?.text ||
  input.text ||
  "";

if (!aiText) {
  return [
    {
      json: {
        message: { text: "" },
        aiError: "OpenAI returned no text in a known response field.",
        raw: input
      }
    }
  ];
}

const cleaned = String(aiText)
  .trim()
  .replace(new RegExp("^```json\\s*", "i"), "")
  .replace(new RegExp("^```\\s*", "i"), "")
  .replace(new RegExp("```$", "i"), "")
  .trim();

const requestContext = $("Prepare OpenAI Generate Request").item.json;
const resolvedOptions = {
  ...requestContext,
  ...(requestContext.generationOptions || {})
};

return [
  {
    json: {
      message: {
        text: cleaned,
        chat: {
          id: resolvedOptions.telegramChatId
        },
        from: {
          id: resolvedOptions.telegramFromId
        },
        message_id: resolvedOptions.originalTelegramMessageId
      },
      generationOptions: {
        saveToDb: resolvedOptions.saveToDb,
        sendDocument: resolvedOptions.sendDocument,
        format: resolvedOptions.format,
        mode: resolvedOptions.mode,
        topic: resolvedOptions.topic,
        categoryId: resolvedOptions.categoryId,
        levelId: resolvedOptions.levelId,
        block: resolvedOptions.block,
        type: resolvedOptions.type,
        researchEnabled: resolvedOptions.researchEnabled,
        reviewEnabled: resolvedOptions.reviewEnabled,
        autoReview: resolvedOptions.autoReview,

