function safeFileName(value) {
  return String(value || "noesis_question")
    .toLowerCase()
    .replace(/[^\p{L}\p{N}]+/gu, "_")
    .replace(/^_+|_+$/g, "")
    .slice(0, 80);
}

function line(value, fallback = "") {
  return String(value ?? fallback);
}

function renderAnswers(data) {
  if (!Array.isArray(data.answers)) {
    return "";
  }

  const lines = ["## Answers", ""];

  data.answers.forEach((answer, index) => {
    const isCorrect =
      Array.isArray(data.correctAnswerIndices) &&
      data.correctAnswerIndices.includes(index);

    if (typeof answer === "object" && answer !== null) {
      lines.push(
        `${index + 1}. ${answer.label || "Option"}${answer.imageUrl ? ` - ${answer.imageUrl}` : ""}${isCorrect ? " [correct]" : ""}`
      );
    } else {
      lines.push(`${index + 1}. ${answer}${isCorrect ? " [correct]" : ""}`);
    }
  });

  lines.push("");
  return lines.join("\n");
}

function renderTypeSpecific(data) {
  const lines = [];

  switch (data.type) {
    case "SINGLE_CHOICE":
    case "MULTIPLE_CHOICE":
    case "IMAGE_CHOICE":
    case "SEQUENCE":
    case "TEN_FACTS":
      if (data.type === "TEN_FACTS" && Array.isArray(data.facts)) {
        lines.push("## Facts", "");
        data.facts.forEach((fact, index) => {
          lines.push(`${index + 1}. ${fact}`);
        });
        lines.push("");
      }

      lines.push(renderAnswers(data));
      break;

    case "TRUE_FALSE":
      lines.push("## Correct Answer", "");
      lines.push(data.correctAnswer ? "true" : "false", "");
      break;

    case "TEXT_INPUT":
    case "FILL_IN_THE_BLANK":
      lines.push("## Correct Answers", "");
      (data.correctAnswers || []).forEach((answer, index) => {
        lines.push(`${index + 1}. ${answer}`);
      });
      lines.push("");
      break;

    case "MATCHING":
      lines.push("## Left Side", "");
      (data.leftSide || []).forEach((item, index) => {
        lines.push(`${index + 1}. ${item}`);
      });
      lines.push("");

      lines.push("## Right Side", "");
      (data.rightSide || []).forEach((item, index) => {
        lines.push(`${index + 1}. ${item}`);
      });
      lines.push("");

      lines.push("## Correct Matches", "");
      (data.correctMatches || []).forEach((match) => {
        lines.push(`- left ${match.leftIndex} -> right ${match.rightIndex}`);
      });
      lines.push("");
      break;

    case "COMPARISON":
      lines.push("## Categories", "");
      (data.categories || []).forEach((item, index) => {
        lines.push(`${index + 1}. ${item}`);
      });
      lines.push("");

      lines.push("## Statements", "");
      (data.statements || []).forEach((item, index) => {
        lines.push(`${index + 1}. ${item.text} -> category ${item.categoryIndex}`);
      });
      lines.push("");
      break;

    case "READING_COMPREHENSION":
      lines.push("## Text 1", "");
      lines.push(line(data.text1, "missing"), "");

      lines.push("## Text 2", "");
      lines.push(line(data.text2, "missing"), "");

      lines.push("## Questions", "");
      (data.questions || []).forEach((q, index) => {
        lines.push(`### ${index + 1}. ${q.question || "Question"}`, "");

        if (Array.isArray(q.answers)) {
          q.answers.forEach((answer, answerIndex) => {
            const isCorrect =
              Array.isArray(q.correctAnswerIndices) &&
              q.correctAnswerIndices.includes(answerIndex);

            lines.push(`${answerIndex + 1}. ${answer}${isCorrect ? " [correct]" : ""}`);
          });
          lines.push("");
        }

        if (q.explanation) {
          lines.push(`Explanation: ${q.explanation}`, "");
        }
      });
      break;

    case "SLIDER_SCALE":
      lines.push("## Text", "");
      lines.push(line(data.text, "missing"), "");

      lines.push("## Sliders", "");
      (data.sliders || []).forEach((slider, index) => {
        lines.push(
          `${index + 1}. ${slider.label || "Slider"}: min=${slider.min}, max=${slider.max}, correct=${slider.correctValue}, tolerance=${slider.tolerance}`
        );
      });
      lines.push("");
      break;

    default:
      lines.push(renderAnswers(data));
      break;
  }

  return lines.filter((x) => x !== "").join("\n") + "\n";
}

