function translitUk(value) {
  return String(value || "")
    .toLowerCase()
    .trim()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\u0449/g, "shch")
    .replace(/\u0448/g, "sh")
    .replace(/\u0447/g, "ch")
    .replace(/\u0436/g, "zh")
    .replace(/\u0445/g, "kh")
    .replace(/\u0446/g, "ts")
    .replace(/\u044e/g, "iu")
    .replace(/\u044f/g, "ia")
    .replace(/\u0454/g, "ie")
    .replace(/\u0457/g, "i")
    .replace(/\u0456/g, "i")
    .replace(/\u0491/g, "g")
    .replace(/\u0439/g, "i")
    .replace(/\u0430/g, "a")
    .replace(/\u0431/g, "b")
    .replace(/\u0432/g, "v")
    .replace(/\u0433/g, "h")
    .replace(/\u0434/g, "d")
    .replace(/\u0435/g, "e")
    .replace(/\u0437/g, "z")
    .replace(/\u0438/g, "y")
    .replace(/\u043a/g, "k")
    .replace(/\u043b/g, "l")
    .replace(/\u043c/g, "m")
    .replace(/\u043d/g, "n")
    .replace(/\u043e/g, "o")
    .replace(/\u043f/g, "p")
    .replace(/\u0440/g, "r")
    .replace(/\u0441/g, "s")
    .replace(/\u0442/g, "t")
    .replace(/\u0443/g, "u")
    .replace(/\u0444/g, "f")
    .replace(/\u044c/g, "");
}

function slugify(value) {
  return translitUk(value)
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 60);
}

function randomId(length = 4) {
  const chars = "abcdefghijklmnopqrstuvwxyz0123456789";
  let result = "";

  for (let i = 0; i < length; i++) {
    result += chars[Math.floor(Math.random() * chars.length)];
  }

  return result;
}

function formatAnswerPreview(data) {
