const input = $input.item.json;
const results = input.results || [];

const previous = $("Load Curated Sources").item.json;
const sourcePolicy = previous.sourcePolicy || input.sourcePolicy || {};
const sourceProfile = sourcePolicy.sourceProfile || "academic";
const rawCuratedSources = previous.curatedSources || [];

const REVIEW_WORD = "\u0440\u0435\u0446\u0435\u043d\u0437\u0456\u044f";
const REVIEW_ON_PUBLICATION = "\u0440\u0435\u0446\u0435\u043d\u0437\u0456\u044f \u043d\u0430 \u0432\u0438\u0434\u0430\u043d\u043d\u044f";

function rebuildAbstract(inverted) {
  if (!inverted || typeof inverted !== "object") return "";

  const words = [];

  for (const [word, positions] of Object.entries(inverted)) {
    for (const pos of positions) {
      words[pos] = word;
    }
  }

  return words.join(" ");
}

function cleanText(value) {
  return String(value || "")
    .replace(/&#13;/g, "")
    .replace(/\\n/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function getHost(url) {
  try {
    return new URL(url).hostname.replace(/^www\./, "").toLowerCase();
  } catch {
    return "";
  }
}

function domainMatches(host, domain) {
  host = String(host || "").toLowerCase();
  domain = String(domain || "").replace(/^www\./, "").toLowerCase();

  return host === domain || host.endsWith("." + domain);
}

function getSourceUrl(source) {
  return (
    source.url ||
    source.landingPageUrl ||
    source.doi ||
    source.id ||
    source.openAlexId ||
    ""
  );
}

function scoreSourceAuthority(source, sourcePolicy) {
  const preferredDomains = sourcePolicy?.preferredDomains || [];
  const strongSourceTypes = sourcePolicy?.strongSourceTypes || [];
  const sourceType = String(source.sourceType || "").toLowerCase();
  const url = getSourceUrl(source);
  const host = getHost(url);

  let authorityScore = 0.35;
  let sourceTier = "weak_web";

  if (preferredDomains.some((domain) => domainMatches(host, domain))) {
    authorityScore += 0.35;
    sourceTier = "preferred_domain";
  }

  if (source.sourceType && strongSourceTypes.includes(source.sourceType)) {
    authorityScore += 0.25;
    sourceTier = "strong_source_type";
  }

  if (/^(official|official_|government_|agency_|institutional_)/.test(sourceType)) {
    authorityScore += 0.25;
    sourceTier = "official_source";
  }

  if (/(reference|encyclopedia|primary_text|museum|cultural_institution)/.test(sourceType)) {
    authorityScore += 0.2;
    sourceTier = sourceTier === "official_source" ? sourceTier : "reference_source";
  }

  if (source.reliability === "high") {
    authorityScore += 0.2;
    sourceTier = "curated";
  }

  if (source.isRetracted === true) {
    authorityScore = 0;
    sourceTier = "retracted";
  }

  return {
    authorityScore: Math.max(0, Math.min(1, authorityScore)),
    sourceTier
  };
}

const curatedSources = rawCuratedSources.map((source) => {
  const authority = scoreSourceAuthority(source, sourcePolicy);

  return {
    ...source,
    authorityScore: authority.authorityScore,
    sourceTier: authority.sourceTier
  };
});

function getQueryCandidates() {
  return [
    input.searchQuery,
    ...(Array.isArray(input.openAlexQueries) ? input.openAlexQueries : []),
    ...(Array.isArray(input.researchQueries) ? input.researchQueries : []),
    input.canonicalTopic,
    input.topic
  ]
    .map((value) => String(value || "").toLowerCase().trim())
    .filter(Boolean);
}

function getRelevanceTerms() {
  const genericTerms = new Set([
    "philosophy",
    "philosophical",
    "interpretation",
    "significance",
    "literature",
    "theory",
    "concept",
    "history",
    "academic",
    "source",
    "sources"
  ]);

  return getQueryCandidates()
    .flatMap((query) => String(query || "").toLowerCase().match(/[a-z?-?????0-9]{4,}/giu) || [])
    .map((term) => term.toLowerCase())
    .filter((term) => !genericTerms.has(term))
    .filter((term, index, all) => all.indexOf(term) === index);
}

function scoreTopicAffinity(item, title, abstractText) {
  const primaryTopic = String(item.primary_topic?.display_name || "").toLowerCase();
  const topicText = [
    primaryTopic,
    ...(Array.isArray(item.topics) ? item.topics.map((topic) => topic.display_name || "") : [])
  ].join(" ").toLowerCase();
  const searchableText = title + " " + abstractText;

  let score = 0;

  if (/classical philosophy|classical antiquity|philosophical ethics|historical, religious, and philosophical/.test(topicText)) {
    score += 3;
  }

  if (/soviet|post-communist|doping in sports|library science|education and cultural studies/.test(primaryTopic)) {
    score -= 4;
  }

  const genericTerms = new Set([
    "ancient",
    "greek",
    "concept",
    "meaning",
    "source",
    "sources",
    "academic",
    "history",
    "philosophy",
    "aesthetics",
    "ethics"
  ]);

  const highSignalTerms = getQueryCandidates()
    .flatMap((query) => String(query || "").toLowerCase().match(/[a-z][a-z0-9-]{5,}/g) || [])
    .filter((term) => term.length <= 30 && !genericTerms.has(term))
    .filter((term, index, all) => all.indexOf(term) === index);

  for (const term of highSignalTerms) {
    if (title.includes(term)) score += term.length >= 9 ? 5 : 2;
    if (abstractText.includes(term)) score += term.length >= 9 ? 2 : 1;
  }

  const wantsKalokagathia = getQueryCandidates().some((query) =>
    String(query || "").toLowerCase().includes("kalokagathia")
  );

  if (wantsKalokagathia && !searchableText.includes("kalokagathia") && searchableText.includes("kalos kagathos")) {
    score -= 2;
  }

  return score;
}

function scoreItem(item) {
  let score = 0;
  let relevanceScore = 0;

  const title = String(item.title || item.display_name || "").toLowerCase();
  const abstractText = rebuildAbstract(item.abstract_inverted_index).toLowerCase();
  const searchableText = title + " " + abstractText;
  const queryCandidates = getQueryCandidates();

  const titleMatches = queryCandidates.some((query) => query.length >= 4 && title.includes(query));
  const abstractMatches = queryCandidates.some((query) => query.length >= 4 && abstractText.includes(query));

  if (titleMatches) relevanceScore += 5;
  if (abstractMatches) relevanceScore += 3;

  const canonicalTopic = String(input.canonicalTopic || "").toLowerCase().trim();

  if (canonicalTopic && searchableText.includes(canonicalTopic)) {
    relevanceScore += title.includes(canonicalTopic) ? 4 : 2;
  }

  const relevanceTerms = getRelevanceTerms();
  const matchedTerms = relevanceTerms.filter((term) => searchableText.includes(term));
  const requiredTermMatches = Math.min(2, Math.max(1, relevanceTerms.length));

  if (matchedTerms.length >= requiredTermMatches) {
    relevanceScore += matchedTerms.length;
  }

  relevanceScore += scoreTopicAffinity(item, title, abstractText);

  // Metadata alone must never make an unrelated OpenAlex result look sufficient.
  if (relevanceScore <= 0) {
    return -100;
  }

  score += relevanceScore;

  if (item.publication_year) score += 1;
  if (item.doi) score += 1;
  if (item.cited_by_count > 0) score += 1;
  if (item.is_retracted === true) score -= 10;

  if (
    title.startsWith(REVIEW_WORD) ||
    abstractText.startsWith(REVIEW_WORD) ||
    abstractText.includes(REVIEW_ON_PUBLICATION)
  ) {
    score -= 4;
  }

  return score;
}

const sources = results
  .map((item) => {
    const title = cleanText(item.title || item.display_name || "Untitled source");

    const abstractText = cleanText(
      rebuildAbstract(item.abstract_inverted_index)
    );

    const topics = (item.topics || [])
      .map((t) => t.display_name)
      .filter(Boolean)
      .slice(0, 5);

    const primaryTopic = item.primary_topic?.display_name || null;

    return {
      raw: item,
      score: scoreItem(item),
      title,
      year: item.publication_year || "unknown",
      citedBy: item.cited_by_count || 0,
      doi: item.doi || null,
      openAlexId: item.id || null,
      primaryTopic,
      topics,
      abstract: abstractText.slice(0, 800)
    };
  })
  .filter((source) => source.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, Math.min(Number(input.sourceLimit || 3), 5))
  .map((source, index) => {
    const authority = scoreSourceAuthority(
      {
        ...source,
        sourceType: "peer_reviewed_article",
        url: source.openAlexId || source.doi,
        isRetracted: source.raw?.is_retracted === true
      },
      sourcePolicy
    );

    return {
      index: index + 1,
      title: source.title,
      year: source.year,
      citedBy: source.citedBy,
      doi: source.doi,
      openAlexId: source.openAlexId,
      primaryTopic: source.primaryTopic,
      topics: source.topics,
      abstract: source.abstract,
      authorityScore: authority.authorityScore,
      sourceTier: authority.sourceTier
    };
  });

const curatedBrief = curatedSources.map((source, index) => {
  return [
    `[C${index + 1}] ${source.title}`,
    source.author ? `Author: ${source.author}` : null,
    source.year ? `Year: ${source.year}` : null,
    source.place || source.publisher
      ? `Publication: ${[source.place, source.publisher].filter(Boolean).join(", ")}`
      : null,
    `Type: ${source.sourceType}`,
    `Reliability: ${source.reliability}`,
    source.note ? `Note: ${source.note}` : null,
    source.evidenceNotes?.length
      ? `Evidence notes:\n- ${source.evidenceNotes.join("\n- ")}`
      : null
  ]
    .filter(Boolean)
    .join("\n");
}).join("\n\n---\n\n");

const openAlexBrief = sources.length
  ? sources
      .map((source) => {
        return [
          `[${source.index}] ${source.title}`,
          `Year: ${source.year}`,
          `Citations: ${source.citedBy}`,
          source.doi ? `DOI: ${source.doi}` : null,
          source.openAlexId ? `OpenAlex: ${source.openAlexId}` : null,
          source.primaryTopic ? `Primary topic: ${source.primaryTopic}` : null,
          source.topics?.length ? `Topics: ${source.topics.join(", ")}` : null,
          source.abstract ? `Abstract: ${source.abstract}` : null
        ]
          .filter(Boolean)
          .join("\n");
      })
      .join("\n\n---\n\n")
  : "";

const sourceBrief = [
  curatedBrief ? "CURATED SOURCES:\n" + curatedBrief : null,
  openAlexBrief ? "OPENALEX SOURCES:\n" + openAlexBrief : null
]
  .filter(Boolean)
  .join("\n\n====================\n\n");

const reviewLikeCount = sources.filter((s) =>
  String(s.abstract || "").toLowerCase().includes(REVIEW_ON_PUBLICATION)
).length;

const weakTopicCount = sources.filter((s) =>
  ["Military Technology and Strategies", "Eastern European Communism and Reforms"]
    .includes(s.primaryTopic)
).length;

const allSources = [...curatedSources, ...sources];

const strongSources = allSources.filter((source) =>
  Number(source.authorityScore || 0) >= 0.65 ||
  [
    "curated",
    "strong_source_type",
    "preferred_domain",
    "official_source",
    "reference_source"
  ].includes(source.sourceTier)
);

const hasCurated = curatedSources.some((source) => source.sourceTier === "curated");
const hasPreferredDomain = allSources.some((source) => source.sourceTier === "preferred_domain");
const hasOfficialSource = allSources.some((source) =>
  source.sourceTier === "official_source" ||
  /^official|official_|government_|agency_|institutional_/.test(String(source.sourceType || "").toLowerCase())
);
const hasReferenceSource = allSources.some((source) =>
  source.sourceTier === "reference_source" ||
  /(reference|encyclopedia|primary_text|museum|cultural_institution)/.test(String(source.sourceType || "").toLowerCase())
);

const minSources = Number(sourcePolicy.minSources || 2);
const allowCuratedSingleSource = sourcePolicy.allowCuratedSingleSource === true;
const allowPopularTrustedSingleSource =
  sourceProfile === "popular_authoritative" &&
  (
    sourcePolicy.allowOfficialSingleSource === true ||
    sourcePolicy.allowReferenceSingleSource === true ||
    sourcePolicy.allowCuratedSingleSource === true
  );
const hasTrustedPopularSource =
  hasCurated ||
  hasPreferredDomain ||
  hasOfficialSource ||
  hasReferenceSource;

let sourceBriefQuality = "insufficient";

if (allSources.length === 0) {
  sourceBriefQuality = "insufficient";
} else if (hasCurated && allowCuratedSingleSource && strongSources.length >= 1) {
  sourceBriefQuality = "curated";
} else if (allowPopularTrustedSingleSource && hasTrustedPopularSource && strongSources.length >= 1) {
  sourceBriefQuality = "ok";
} else if (strongSources.length >= minSources) {
  sourceBriefQuality = "ok";
} else if (strongSources.length >= 1) {
  sourceBriefQuality = "weak";
}

if (reviewLikeCount >= 2 || weakTopicCount >= 2) {
  sourceBriefQuality = sourceBriefQuality === "ok" ? "weak" : sourceBriefQuality;
}

let sourceConfidence = 0.3;

if (sourceBriefQuality === "curated") {
  sourceConfidence = 0.85;
} else if (sourceBriefQuality === "ok") {
  sourceConfidence = sourceProfile === "popular_authoritative" ? 0.72 : 0.7;
} else if (sourceBriefQuality === "weak") {
  sourceConfidence = sourceProfile === "popular_authoritative" ? 0.5 : 0.45;
} else if (sourceBriefQuality === "insufficient") {
  sourceConfidence = 0.15;
}

if (curatedSources.length >= 2) {
  sourceConfidence += 0.05;
}

if (hasOfficialSource || hasReferenceSource || hasPreferredDomain) {
  sourceConfidence += 0.05;
}

if (sources.some((s) => s.doi)) {
  sourceConfidence += 0.05;
}

if (sources.some((s) => Number(s.citedBy || 0) > 0)) {
  sourceConfidence += 0.05;
}

if (reviewLikeCount >= 2) {
  sourceConfidence -= 0.1;
}

if (weakTopicCount >= 2) {
  sourceConfidence -= 0.1;
}

sourceConfidence = Math.max(
  0,
  Math.min(1, Number(sourceConfidence.toFixed(2)))
);

return [
  {
    json: {
      ...input,
      retrievedSources: sources,
      curatedSources,
      curatedSourceCount: curatedSources.length,
      hasCuratedSources: curatedSources.length > 0,
      sourceBrief,
      sourceBriefStatus:
        sourceBriefQuality === "insufficient"
          ? "insufficient_sources"
          : sourceBriefQuality,
      sourceBriefQuality,
      sourceConfidence,
      sourceBriefWarnings: {
        reviewLikeCount,
        weakTopicCount,
        rawOpenAlexResultCount: Array.isArray(results) ? results.length : 0
      },
      sourcePolicy,
      sourceAuthoritySummary: {
        totalSources: allSources.length,
        strongSources: strongSources.length,
        minSources,
        hasCurated,
        hasPreferredDomain,
        hasOfficialSource,
        hasReferenceSource,
        sourceProfile
      }
    }
  }
];

const input = $input.item.json;

const sourceSet = input || {};

const isActive = sourceSet.status === "active";
const sources = Array.isArray(sourceSet.sources) && isActive
  ? sourceSet.sources
  : [];

const previous = $("Build Curated Source Set Key").item.json;

return [
  {
    json: {
      ...previous,
      curatedSourceSet: {
        sourceSetId: sourceSet.sourceSetId || previous.curatedSourceSetKey || null,
        discipline: sourceSet.discipline || previous.sourcePolicy?.discipline || null,
        title: sourceSet.title || null,
        status: sourceSet.status || "missing",
        reliability: sourceSet.reliability || null,
        keywordCount: Array.isArray(sourceSet.keywords) ? sourceSet.keywords.length : 0,
        sourceCount: sources.length,
        version: sourceSet.version || null,
        updatedAt: sourceSet.updatedAt || null
      },
      curatedSources: sources,
      curatedSourceCount: sources.length,
      hasCuratedSources: sources.length > 0
    }
  }
];

const input = $input.item.json;

const generatedText = String(input.message?.text || "").trim();

let generatedJson;

try {
  generatedJson = JSON.parse(generatedText);
} catch (error) {
  return [
    {
      json: {
        ok: false,
        reviewError: "AI output is not valid JSON before review.",
        generatedText,
        telegramChatId: input.message?.chat?.id || input.generationOptions?.telegramChatId || null,
        generationOptions: input.generationOptions || null
      }
    }
  ];
}

const parseOptions = input.generationOptions || input;

const sourceBrief =
  input.sourceBrief ||
  parseOptions.sourceBrief ||
  "";

const sourceBriefQuality =
  input.sourceBriefQuality ||
  parseOptions.sourceBriefQuality ||
  "none";

const sourceBriefStatus =
  input.sourceBriefStatus ||
  parseOptions.sourceBriefStatus ||
  "none";

const sourceAuthoritySummary =
  input.sourceAuthoritySummary ||
  input.reviewDecision?.sourceAuthoritySummary ||
  parseOptions.sourceAuthoritySummary ||
  null;

const sourcePolicy =
  input.sourcePolicy ||
  parseOptions.sourcePolicy ||
  null;

const reviewPrompt = [
  "You are Noesis Source-Backed Reviewer.",
  "",
  "Your task is not to rewrite the question. Your task is to evaluate its quality and safety.",
  "",
  `Review reason: ${input.reviewDecision?.reviewReason || "unknown"}`,
  `Source confidence: ${input.reviewDecision?.sourceConfidence ?? parseOptions.sourceConfidence ?? "unknown"}`,
  `Source status: ${sourceBriefStatus}`,
  `Source brief quality: ${sourceBriefQuality}`,
  `Source authority summary: ${JSON.stringify(sourceAuthoritySummary)}`,
  `Source discipline: ${sourcePolicy?.discipline || input.reviewDecision?.sourcePolicyDiscipline || "unknown"}`,
  `Should review: ${input.reviewDecision?.shouldReview}`,
  "",
  "CHECKLIST:",
  "- factual correctness;",
  "- consistency with SOURCE BRIEF;",
  "- whether the correct answer is unambiguous;",
  "- distractor quality;",
  "- explanation quality;",
  "- pedagogical value;",
  "- hallucination risk;",
  "- whether the generated question makes claims that are not supported by SOURCE BRIEF.",
  "",
  "SOURCE BRIEF:",
  sourceBrief || "none",
  "",
  "GENERATED QUESTION JSON:",
  JSON.stringify(generatedJson, null, 2),
  "",
  "Return only valid JSON. Do not use Markdown.",
  "",
  "Required JSON shape:",
  JSON.stringify(
    {
      approved: true,
      confidence: 0.85,
      factualReliability: 0.9,
      pedagogicalQuality: 0.8,
      distractorQuality: 0.8,
      ambiguityRisk: 0.1,
      hallucinationRisk: 0.1,
      verdict: "pass",
      issues: [],
      recommendations: []
    },
    null,
    2
  ),
  "",
  "DECISION RULES:",
  "- verdict = pass only if the question can safely proceed to human moderation.",
  "- verdict = revise if the question needs correction but is not fundamentally unsafe.",
  "- verdict = reject if the question is factually unsafe, unsupported, or has an ambiguous correct answer.",
  "- If sourceBriefQuality is insufficient or sourceBriefStatus is insufficient_sources, verdict must not be pass for a factual question.",
  "- If sourceBriefQuality is weak, verdict pass is allowed only for a broad question directly supported by SOURCE BRIEF.",
  "- If SOURCE BRIEF does not directly support the correct answer or explanation, verdict must be revise or reject.",
  "- If more than one answer could reasonably be correct, verdict must be revise or reject.",
  "- The generated question is in Ukrainian; evaluate the Ukrainian text as written.",
  "- Do not penalize the question merely because the review instructions are in English."
].join("\n");

return [
  {
    json: {
      ...input,
