parameters.jsCode:
const original = $("Load Curated Sources").item.json;
const items = $input.all();
const mergedResults = [];
const seen = new Set();
const errors = [];

for (const item of items) {
  const searchResponse = item.json || {};
  const hasOpenAlexError =
    Boolean(searchResponse.error) ||
    Boolean(searchResponse.errorMessage) ||
    Boolean(searchResponse.message && !Array.isArray(searchResponse.results));

  if (hasOpenAlexError) {
    errors.push({
      error: searchResponse.error || null,
      errorMessage: searchResponse.errorMessage || searchResponse.message || "OpenAlex request failed.",
      httpCode: searchResponse.httpCode || searchResponse.statusCode || null
    });
    continue;
  }

  const results = Array.isArray(searchResponse.results)
    ? searchResponse.results
    : [];

  for (const result of results) {
    const key = result.id || result.doi || result.display_name || result.title;
    if (!key || seen.has(key)) continue;
    seen.add(key);
    mergedResults.push(result);
  }
}

return [
  {
    json: {
      ...original,
      openAlexResponse: {
        queries: original.openAlexQueries || [original.searchQuery].filter(Boolean),
        requestCount: items.length,
        mergedResultCount: mergedResults.length,
        errors
      },
      openAlexAvailable: errors.length < items.length,
      openAlexError: errors.length && errors.length === items.length
        ? errors[0]
        : null,
      results: mergedResults
    }
  }
];

