const input = $input.item.json;

function normalize(value) {
  return String(value || "")
    .toLowerCase()
    .trim()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ");
}

function translitUk(value) {
  return normalize(value)
    .replace(/\u0449/g, "shch")
    .replace(/\u0448/g, "sh")
    .replace(/\u0447/g, "ch")
    .replace(/\u0436/g, "zh")
    .replace(/\u0445/g, "kh")
    .replace(/\u0446/g, "ts")
    .replace(/\u044e/g, "iu")
    .replace(/\u044f/g, "ia")
    .replace(/\u0454/g, "ie")
    .replace(/\u0457/g, "i")
    .replace(/\u0456/g, "i")
    .replace(/\u0491/g, "g")
    .replace(/\u0439/g, "i")
    .replace(/\u0430/g, "a")
    .replace(/\u0431/g, "b")
    .replace(/\u0432/g, "v")
    .replace(/\u0433/g, "h")
    .replace(/\u0434/g, "d")
    .replace(/\u0435/g, "e")
    .replace(/\u0437/g, "z")
    .replace(/\u0438/g, "y")
    .replace(/\u043a/g, "k")
    .replace(/\u043b/g, "l")
    .replace(/\u043c/g, "m")
    .replace(/\u043d/g, "n")
    .replace(/\u043e/g, "o")
    .replace(/\u043f/g, "p")
    .replace(/\u0440/g, "r")
    .replace(/\u0441/g, "s")
    .replace(/\u0442/g, "t")
    .replace(/\u0443/g, "u")
    .replace(/\u0444/g, "f")
    .replace(/\u044c/g, "");
}

function unique(values) {
  return [...new Set(values.map((v) => String(v || "").trim()).filter(Boolean))];
}

const topic = String(input.topic || "").trim();
const normalizedTopic = normalize(topic);
const transliteratedTopic = translitUk(topic);
const discipline = input.sourcePolicy?.discipline || "general";

const researchQueries = [topic];

if (transliteratedTopic && transliteratedTopic !== normalizedTopic) {
  researchQueries.push(transliteratedTopic);
}

if (discipline === "philosophy") {
  researchQueries.push(`${topic} philosophy`);
  researchQueries.push(`${transliteratedTopic} philosophy`);
  researchQueries.push(`${topic} religion`);
  researchQueries.push(`${transliteratedTopic} religion`);
  researchQueries.push(`${topic} anthropology`);
  researchQueries.push(`${transliteratedTopic} anthropology`);
}

if (discipline === "history") {
  researchQueries.push(`${topic} history`);
  researchQueries.push(`${transliteratedTopic} history`);
  researchQueries.push(`${topic} culture`);
  researchQueries.push(`${transliteratedTopic} culture`);
}

if (discipline === "science") {
  researchQueries.push(`${topic} science`);
  researchQueries.push(`${transliteratedTopic} research`);
}

const aliasRules = [
  {
    match: ["фейєрбах", "feiierbakh", "feyerbach", "feuerbach"],
    queries: [
      "Ludwig Feuerbach philosophy",
      "Ludwig Feuerbach The Essence of Christianity",
      "Feuerbach religion anthropology",
      "Feuerbach materialism"
    ]
  },
  {
    match: ["кант", "kant"],
    queries: [
      "Immanuel Kant philosophy",
      "Kant epistemology",
      "Kant Critique of Pure Reason",
      "Kant transcendental idealism"
    ]
  },
  {
    match: ["київська русь", "kyivska rus", "kyivan rus", "kievan rus"],
    queries: [
      "Kievan Rus history",
      "Kyivan Rus history",
      "Kyiv Rus medieval state",
      "Kievan Rus culture"
    ]
  }
];

for (const rule of aliasRules) {
  const matched = rule.match.some((item) => {
    const normalizedMatch = normalize(item);
    const transliteratedMatch = translitUk(item);

    return (
      normalizedTopic.includes(normalizedMatch) ||
      transliteratedTopic.includes(normalizedMatch) ||
      normalizedTopic.includes(transliteratedMatch) ||
      transliteratedTopic.includes(transliteratedMatch)
    );
  });

  if (matched) {
    researchQueries.push(...rule.queries);
  }
}

const finalQueries = unique(researchQueries).slice(0, 5);

return [
  {
    json: {
      ...input,
      searchQuery: finalQueries[0],
      researchQueries: finalQueries,
      researchQueryCount: finalQueries.length,
      researchQueryStrategy: {
        topic,
        normalizedTopic,
        transliteratedTopic,
        discipline
      }
    }
  }
];

const input = $input.first().json;

const aiText =
  input.output_text ||
  input.output?.[0]?.content?.[0]?.text ||
  input.output?.[0]?.content?.find?.((c) => c.type === "output_text")?.text ||
  input.text ||
  "";

const original = $("Prepare Research Plan Request").item.json;
const sourceProfile = original.sourcePolicy?.sourceProfile || "academic";

function fallbackPlan(reason) {
  const topic = String(original.topic || "").trim();
  const popular = sourceProfile === "popular_authoritative";

  return {
    canonicalTopic: topic,
    detectedLanguage: "unknown",
    discipline: original.sourcePolicy?.discipline || "general",
    sourceProfile,
    searchLanguage: "en",
    searchQueries: [topic].filter(Boolean),
    referenceQueries: [topic].filter(Boolean),
    officialSourceHints: [],
    requiredEvidence: [topic].filter(Boolean),
    sourceSelectionCriteria: {
      preferredSourceTypes: popular
        ? ["official_source", "institutional_reference", "encyclopedia_reference", "curated_reference"]
        : ["peer_reviewed_article", "academic_book", "academic_reference"],
      rejectIf: [
        "book review only",
        "unrelated discipline",
        "no direct support for the topic"
      ]
    },
    fallbackReason: reason
  };
}

let researchPlan;

try {
  const fence = String.fromCharCode(96).repeat(3);
  const cleaned = String(aiText)
    .trim()
    .replace(new RegExp("^" + fence + "json\\s*", "i"), "")
    .replace(new RegExp("^" + fence + "\\s*", "i"), "")
    .replace(new RegExp(fence + "$", "i"), "")
    .trim();

  researchPlan = JSON.parse(cleaned);
} catch (error) {
  researchPlan = fallbackPlan("research_plan_json_parse_failed");
}

if (!researchPlan || typeof researchPlan !== "object") {
  researchPlan = fallbackPlan("research_plan_not_object");
}

function normalizeList(value) {
  return [...new Set(
    (Array.isArray(value) ? value : [])
      .map((item) => String(item || "").trim())
      .filter(Boolean)
  )].slice(0, 8);
}

function normalizeSpace(value) {
  return String(value || "")
    .replace(/\s+/g, " ")
    .trim();
}

function uniquePush(list, value) {
  const cleaned = normalizeSpace(value);
  if (!cleaned) return;
  const key = cleaned.toLowerCase();
  if (!list.some((item) => item.toLowerCase() === key)) {
    list.push(cleaned);
  }
}

function addSpellingVariants(list, value) {
  const text = normalizeSpace(value);
  const lower = text.toLowerCase();

  if (!text) return;

  if (lower.includes("calocagathia")) {
    uniquePush(list, text.replace(/calocagathia/ig, "kalokagathia"));
    uniquePush(list, "kalokagathia");
    uniquePush(list, "kalokagathia ethics");
    uniquePush(list, "kalos kagathos");
  }

  if (lower.includes("kalokagathia")) {
    uniquePush(list, text.replace(/kalokagathia/ig, "calocagathia"));
    uniquePush(list, "kalokagathia");
    uniquePush(list, "kalokagathia ethics");
    uniquePush(list, "kalos kagathos");
  }
}

function inferOpenAlexQueries(plan, original) {
  const candidates = [];
  const topic = normalizeSpace(original.topic);
  const canonicalTopic = normalizeSpace(plan.canonicalTopic || topic);

  uniquePush(candidates, canonicalTopic);
  uniquePush(candidates, topic);

  for (const query of normalizeList(plan.searchQueries)) {
    uniquePush(candidates, query);

    const firstTerm = String(query || "").match(/^[A-Z][A-Za-z\-]{5,}/)?.[0];
    if (firstTerm && !/^(Ancient|Greek|Concept|Theory|Philosophy|History)$/i.test(firstTerm)) {
      uniquePush(candidates, firstTerm);
    }
  }

  const topicForVariantMatch = (topic + " " + canonicalTopic).toLowerCase();
  if (topicForVariantMatch.includes("\u043a\u0430\u043b\u043e\u043a\u0430\u0433\u0430\u0442")) {
    uniquePush(candidates, "kalokagathia");
    uniquePush(candidates, "kalokagathia ethics");
    uniquePush(candidates, "kalos kagathos");
  }

  for (const query of [...candidates]) {
    addSpellingVariants(candidates, query);
  }

  function queryPriority(query) {
    const value = String(query || "").toLowerCase();
    const words = value.split(/\s+/).filter(Boolean).length;
    let score = 0;

    if (/^[a-z0-9 ,.'\-]+$/i.test(query)) score += 4;
    if (!/[\u0400-\u04ff]/.test(query)) score += 2;
    if (words <= 3) score += 3;
    if (value.includes("kalokagathia")) score += 10;
    if (value.includes("kalos kagathos")) score += 8;
    if (value.includes("calocagathia")) score += 6;
    if (value.length > 60) score -= 3;
    if (/\b(concept|meaning|significance|source|sources|academic)\b/.test(value)) score -= 1;

    return score;
  }

  return candidates
    .sort((a, b) => queryPriority(b) - queryPriority(a))
    .slice(0, 5);
}

researchPlan.sourceProfile = researchPlan.sourceProfile || sourceProfile;
researchPlan.searchQueries = normalizeList(researchPlan.searchQueries);
researchPlan.referenceQueries = normalizeList(researchPlan.referenceQueries);
researchPlan.officialSourceHints = normalizeList(researchPlan.officialSourceHints);

if (researchPlan.searchQueries.length === 0) {
  researchPlan.searchQueries = [String(original.topic || "").trim()].filter(Boolean);
}

if (researchPlan.referenceQueries.length === 0) {
  researchPlan.referenceQueries = researchPlan.searchQueries;
}

const openAlexQueries = inferOpenAlexQueries(researchPlan, original);
const searchQuery = openAlexQueries[0] || researchPlan.searchQueries[0] || original.topic;

return [
  {
    json: {
      ...original,
      researchPlan,
      searchQuery,
      researchQueries: researchPlan.searchQueries,
      openAlexQueries,
      referenceQueries: researchPlan.referenceQueries,
      officialSourceHints: researchPlan.officialSourceHints,
      researchQueryCount: researchPlan.searchQueries.length,
      openAlexQueryCount: openAlexQueries.length,
      canonicalTopic: researchPlan.canonicalTopic || original.topic,
      requiredEvidence: Array.isArray(researchPlan.requiredEvidence)
        ? researchPlan.requiredEvidence
        : []
    }
  }
];

const input = $input.item.json;

function normalizeQuestionType(value) {
  const raw = String(value || "")
    .trim()
    .toUpperCase()
    .replace(/[\s-]+/g, "_")
    .replace(/_+/g, "_");

  const aliases = {
    SINGLECHOICE: "SINGLE_CHOICE",
    SINGLE_CHOICE: "SINGLE_CHOICE",

    MULTIPLECHOICE: "MULTIPLE_CHOICE",
    MULTIPLE_CHOICE: "MULTIPLE_CHOICE",

    TRUEFALSE: "TRUE_FALSE",
    TRUE_FALSE: "TRUE_FALSE",

    TEXTINPUT: "TEXT_INPUT",
    TEXT_INPUT: "TEXT_INPUT",

    FILLINTHEBLANK: "FILL_IN_THE_BLANK",
    FILL_IN_THE_BLANK: "FILL_IN_THE_BLANK",

    IMAGECHOICE: "IMAGE_CHOICE",
    IMAGE_CHOICE: "IMAGE_CHOICE",

    READINGCOMPREHENSION: "READING_COMPREHENSION",
    READING_COMPREHENSION: "READING_COMPREHENSION",

    SLIDERSCALE: "SLIDER_SCALE",
    SLIDER_SCALE: "SLIDER_SCALE",

    TENFACTS: "TEN_FACTS",
    TEN_FACTS: "TEN_FACTS",

    SEQUENCE: "SEQUENCE",
    MATCHING: "MATCHING",
    COMPARISON: "COMPARISON"
  };

  return aliases[raw] || raw;
}

function formatAnswerPreview(data) {
  if (Array.isArray(data.answers)) {
    return data.answers
      .map((answer, index) => {
        const label = typeof answer === "object"
          ? answer.label || answer.text || JSON.stringify(answer)
          : answer;

        const isCorrect =
          Array.isArray(data.correctAnswerIndices) &&
          data.correctAnswerIndices.includes(index);

        return `${index + 1}. ${label}${isCorrect ? " - correct" : ""}`;
      })
      .join("\n");
  }

  if (data.type === "TRUE_FALSE") {
    return `Correct answer: ${data.correctAnswer ? "true" : "false"}`;
  }

  if (Array.isArray(data.correctAnswers)) {
    return `Correct answers: ${data.correctAnswers.join(", ")}`;
  }

  if (data.type === "MATCHING") {
    return [
      "Left side:",
      ...(data.leftSide || []).map((x, i) => `${i + 1}. ${x}`),
      "",
      "Right side:",
      ...(data.rightSide || []).map((x, i) => `${i + 1}. ${x}`),
      "",
      "Correct matches:",
      ...(data.correctMatches || []).map((m) => {
        return `${Number(m.leftIndex) + 1} -> ${Number(m.rightIndex) + 1}`;
      })
    ].join("\n");
  }

  if (data.type === "COMPARISON") {
    return [
      "Categories:",
      ...(data.categories || []).map((x, i) => `${i + 1}. ${x}`),
      "",
      "Statements:",
      ...(data.statements || []).map((x, i) => {
        return `${i + 1}. ${x.text} [category ${Number(x.categoryIndex) + 1}]`;
      })
    ].join("\n");
  }

  if (data.type === "READING_COMPREHENSION") {
    return (data.questions || [])
      .map((q, i) => {
        return [
          `${i + 1}. ${q.question}`,
          ...(q.answers || []).map((a, j) => {
            const isCorrect =
              Array.isArray(q.correctAnswerIndices) &&
              q.correctAnswerIndices.includes(j);

            return `   ${j + 1}. ${a}${isCorrect ? " - correct" : ""}`;
          })
        ].join("\n");
      })
      .join("\n\n");
  }

  if (data.type === "SLIDER_SCALE") {
    return (data.sliders || [])
      .map((s, i) => {
        return `${i + 1}. ${s.label}: ${s.correctValue} (${s.min}-${s.max}, tolerance ${s.tolerance})`;
      })
      .join("\n");
  }

  if (data.type === "TEN_FACTS") {
    return [
      "Facts:",
      ...(data.facts || []).map((fact, i) => `${i + 1}. ${fact}`),
      "",
      "Answer options:",
      ...(data.answers || []).map((answer, i) => {
        const isCorrect =
          Array.isArray(data.correctAnswerIndices) &&
          data.correctAnswerIndices.includes(i);

        return `${i + 1}. ${answer}${isCorrect ? " - correct" : ""}`;
      })
    ].join("\n");
  }

  return "Preview is not configured for this question type.";
}

function formatReason(value) {
  return String(value || "")
    .replace(/_/g, " ")
    .trim();
}

const documentData = {
  ...(input.documentData || {})
};

documentData.type = normalizeQuestionType(
  documentData.type || input.generationOptions?.type
