const input = $input.item.json;

function norm(value) {
  return String(value || "")
    .toLowerCase()
    .trim();
}

function toIntOrNull(value) {
  const n = Number(value);
  return Number.isInteger(n) && n > 0 ? n : null;
}

function detectCategory(input) {
  const explicit = norm(input.categoryId);

  if (explicit && explicit !== "auto" && explicit !== "undefined" && explicit !== "null") {
    return explicit;
  }

  const discipline = input.sourcePolicy?.discipline || "general";

  if (discipline === "philosophy") return "philosophy";
  if (discipline === "science" || discipline === "astronomy" || discipline === "biomedicine") return "science";
  if (discipline === "culture") return "culture";

  return "erudite";
}

function detectLevel(input) {
  const explicit = norm(input.levelId);

  if (explicit && explicit !== "auto" && explicit !== "undefined" && explicit !== "null") {
    return String(input.levelId);
  }

  // levelId is a structural Firestore level/quiz path, not difficulty.
  return "1";
}

function detectDifficulty(input) {
  const explicit = toIntOrNull(input.difficulty);

  if (explicit) {
    return Math.max(1, Math.min(5, explicit));
  }

  const topic = norm(input.topic);
  const type = norm(input.type)
    .replace(/[\s-]+/g, "_")
    .replace(/_+/g, "_");

  const sourceProfile = input.sourcePolicy?.sourceProfile || "academic";
  const discipline = input.sourcePolicy?.discipline || "general";

  let score = 1;

  if (sourceProfile === "academic") {
    score += 1;
  }

  if (
    [
      "comparison",
      "matching",
      "sequence",
      "reading_comprehension",
      "slider_scale",
      "ten_facts"
    ].includes(type)
  ) {
    score += 1;
  }

  if (
    topic.length > 80 ||
    topic.includes(",") ||
    topic.includes("критика") ||
    topic.includes("теорія") ||
    topic.includes("концепція") ||
    topic.includes("антропологіч") ||
    topic.includes("трансцендент") ||
    topic.includes("епістемолог") ||
    topic.includes("метафіз") ||
    topic.includes("онтолог")
  ) {
    score += 1;
  }

  if (discipline === "philosophy" && score < 2) {
    score = 2;
  }

  return Math.max(1, Math.min(5, score));
}

function detectBlock(input) {
  const explicit = norm(input.block);

  if (explicit && explicit !== "auto" && /^[a-z]$/i.test(explicit)) {
    return explicit.toUpperCase();
  }

  return "A";
}

const discipline = input.sourcePolicy?.discipline || "general";
const sourceProfile = input.sourcePolicy?.sourceProfile || null;

const targetCategoryId = detectCategory(input);
const targetLevelId = detectLevel(input);
const targetBlock = detectBlock(input);
const difficulty = detectDifficulty(input);

const explicitNum = toIntOrNull(input.explicitNum);

return [
  {
    json: {
      ...input,

      targetCategoryId,
      targetLevelId,
      targetBlock,
      explicitNum,

      categoryId: targetCategoryId,
      levelId: String(targetLevelId),
