}

function getField(q, name) {
  return (
    q[name] ??
    q.documentData?.[name] ??
    q.data?.[name] ??
    q.fields?.[name] ??
    null
  );
}

function normalizeBlock(value) {
  const raw = String(value || "A").trim().toUpperCase();
  if (raw === "AUTO") return "A";
  if (/^[A-Z]$/.test(raw)) return raw;
  return "A";
}

function isActivePendingQuestion(q, targetCollectionPath, categoryId, levelId) {
  const status = String(getField(q, "status") || q.status || "pending_review");
  if (["approved", "rejected", "revised"].includes(status)) return false;
  const pendingTarget = q.targetCollectionPath || q.collectionPath || null;
  if (pendingTarget) return pendingTarget === targetCollectionPath;
  return (
    String(getField(q, "categoryId") || "") === String(categoryId) &&
    String(getField(q, "levelId") || "") === String(levelId)
  );
}

