function normalizeType(value) {
  const raw = String(value || "")
    .trim()
    .toUpperCase()
    .replace(/[\s-]+/g, "_")
    .replace(/_+/g, "_");

  const aliases = {
    AUTO: "AUTO",
    ADVANCED: "ADVANCED",

    SINGLECHOICE: "SINGLE_CHOICE",
    SINGLE_CHOICE: "SINGLE_CHOICE",

    MULTIPLECHOICE: "MULTIPLE_CHOICE",
    MULTIPLE_CHOICE: "MULTIPLE_CHOICE",

    TRUEFALSE: "TRUE_FALSE",
    TRUE_FALSE: "TRUE_FALSE",

    FILLINTHEBLANK: "FILL_IN_THE_BLANK",
    FILL_IN_THE_BLANK: "FILL_IN_THE_BLANK",

    TEXTINPUT: "TEXT_INPUT",
    TEXT_INPUT: "TEXT_INPUT",

    IMAGECHOICE: "IMAGE_CHOICE",
    IMAGE_CHOICE: "IMAGE_CHOICE",

    READINGCOMPREHENSION: "READING_COMPREHENSION",
    READING_COMPREHENSION: "READING_COMPREHENSION",

    SLIDERSCALE: "SLIDER_SCALE",
    SLIDER_SCALE: "SLIDER_SCALE",

    TENFACTS: "TEN_FACTS",
    TEN_FACTS: "TEN_FACTS",

    SEQUENCE: "SEQUENCE",
    MATCHING: "MATCHING",
    COMPARISON: "COMPARISON"
  };

  return aliases[raw] || raw;
}

function weightedPick(weights) {
  const entries = Object.entries(weights);
  const total = entries.reduce((sum, [, weight]) => sum + weight, 0);
  let roll = Math.random() * total;

  for (const [type, weight] of entries) {
    roll -= weight;

    if (roll <= 0) {
      return type;
    }
  }

  return entries[0][0];
}

const commonTypeWeights = {
  SINGLE_CHOICE: 45,
  MULTIPLE_CHOICE: 15,
  TRUE_FALSE: 10,
  TEXT_INPUT: 8,
  FILL_IN_THE_BLANK: 8,
  MATCHING: 5,
  SEQUENCE: 4,
  COMPARISON: 4,
  IMAGE_CHOICE: 1
};

const advancedTypeWeights = {
  READING_COMPREHENSION: 50,
  TEN_FACTS: 35,
  SLIDER_SCALE: 15
};

const allowedTypes = [
  "SINGLE_CHOICE",
  "MULTIPLE_CHOICE",
  "TRUE_FALSE",
  "SEQUENCE",
  "MATCHING",
  "COMPARISON",
  "TEXT_INPUT",
  "FILL_IN_THE_BLANK",
  "IMAGE_CHOICE",
  "READING_COMPREHENSION",
  "SLIDER_SCALE",
  "TEN_FACTS"
];

const requestedType = normalizeType(input.type || "SINGLE_CHOICE");

let resolvedType = requestedType;
let typeAuto = false;
let typePool = "explicit";

if (requestedType === "AUTO") {
  resolvedType = weightedPick(commonTypeWeights);
  typeAuto = true;
  typePool = "common";
}

if (requestedType === "ADVANCED") {
  resolvedType = weightedPick(advancedTypeWeights);
  typeAuto = true;
  typePool = "advanced";
}

if (!allowedTypes.includes(resolvedType)) {
  resolvedType = "SINGLE_CHOICE";
  typeAuto = true;
  typePool = "fallback";
}

return [
  {
    json: {
      ...input,
      requestedType,
      type: resolvedType,
      resolvedQuestionType: resolvedType,
      questionTypeResolution: {
        requestedType,
        resolvedType,
        auto: typeAuto,
        pool: typePool
      }
    }
  }
];

