function shuffleOrder(length) {
  const order = Array.from({ length }, (_, index) => index);

  // Fisher-Yates gives each position the same probability; no answer slot is favored.
  for (let i = order.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [order[i], order[j]] = [order[j], order[i]];
  }

  return order;
}

function remapIndices(indices, order) {
  const oldToNew = new Map();
  order.forEach((oldIndex, newIndex) => oldToNew.set(oldIndex, newIndex));

  return indices
    .map((index) => oldToNew.get(Number(index)))
    .filter((index) => Number.isInteger(index))
    .sort((a, b) => a - b);
}

function shuffleAnswers(data) {
  if (!data || typeof data !== "object") return data;

  const type = String(data.type || "").toUpperCase();

  if (
    ["SINGLE_CHOICE", "MULTIPLE_CHOICE", "IMAGE_CHOICE", "TEN_FACTS"].includes(type) &&
    Array.isArray(data.answers) &&
    Array.isArray(data.correctAnswerIndices) &&
    data.answers.length > 1
  ) {
    const order = shuffleOrder(data.answers.length);
    data.answers = order.map((oldIndex) => data.answers[oldIndex]);
    data.correctAnswerIndices = remapIndices(data.correctAnswerIndices, order);
  }

  if (type === "MATCHING" && Array.isArray(data.rightSide) && Array.isArray(data.correctMatches)) {
    const order = shuffleOrder(data.rightSide.length);
    const oldToNew = new Map();
    order.forEach((oldIndex, newIndex) => oldToNew.set(oldIndex, newIndex));

    data.rightSide = order.map((oldIndex) => data.rightSide[oldIndex]);
    data.correctMatches = data.correctMatches.map((match) => ({
      ...match,
      rightIndex: oldToNew.get(Number(match.rightIndex))
    }));
  }

  if (type === "COMPARISON" && Array.isArray(data.statements) && data.statements.length > 1) {
    const order = shuffleOrder(data.statements.length);
    data.statements = order.map((oldIndex) => data.statements[oldIndex]);
  }

  if (type === "READING_COMPREHENSION" && Array.isArray(data.questions)) {
    data.questions = data.questions.map((question) => {
      if (
        question &&
        Array.isArray(question.answers) &&
        Array.isArray(question.correctAnswerIndices) &&
        question.answers.length > 1
      ) {
        const order = shuffleOrder(question.answers.length);

        return {
          ...question,
          answers: order.map((oldIndex) => question.answers[oldIndex]),
          correctAnswerIndices: remapIndices(question.correctAnswerIndices, order)
        };
      }

      return question;
    });
  }

  return data;
}

return $input.all().map((item) => {
  const json = { ...item.json };
  const documentData = json.documentData && typeof json.documentData === "object"
    ? { ...json.documentData }
    : json.documentData;

  if (documentData && typeof documentData === "object") {
    json.documentData = shuffleAnswers(documentData);
  }

  return { json };
});

