function unique(values) {
  const out = [];
  for (const value of values) {
    const cleaned = String(value || "").replace(/\s+/g, " ").trim();
    if (!cleaned) continue;
    if (!out.some((item) => item.toLowerCase() === cleaned.toLowerCase())) {
      out.push(cleaned);
    }
  }
  return out;
}

