  ...(Array.isArray(input.openAlexQueries) ? input.openAlexQueries : []),
  input.searchQuery,
  ...(Array.isArray(input.researchQueries) ? input.researchQueries : []),
  input.canonicalTopic,
  input.topic
]).slice(0, 5);

